     7→#ifndef _SOFA_PBRPC_RPC_CONTROLLER_IMPL_H_
     8→#define _SOFA_PBRPC_RPC_CONTROLLER_IMPL_H_
     9→
    10→#include <deque>
    11→#include <list>
    12→
    13→#include <google/protobuf/descriptor.h>
    14→
    15→#include <sofa/pbrpc/common_internal.h>
    16→#include <sofa/pbrpc/buffer.h>
    17→#include <sofa/pbrpc/rpc_controller.h>
    18→#include <sofa/pbrpc/rpc_endpoint.h>
    19→#include <sofa/pbrpc/rpc_error_code.h>
    20→#include <sofa/pbrpc/rpc_option.pb.h>
    21→#include <sofa/pbrpc/wait_event.h>
    22→
    23→namespace sofa {
    24→namespace pbrpc {
    25→
    26→#define CompressTypeAuto ((CompressType)-1)
    27→
    28→class RpcControllerImpl : public sofa::pbrpc::enable_shared_from_this<RpcControllerImpl>
    29→{
    30→public:
    31→    typedef boost::function<void(const RpcControllerImplPtr&)> InternalDoneCallback;
    32→
    33→public:
    34→    RpcControllerImpl()
    35→        : _sequence_id(0)
    36→        , _error_code(RPC_SUCCESS)
    37→        , _is_done(NOT_DONE)
    38→        , _is_request_sent(false)
    39→        , _sent_bytes(0)
    40→        , _is_start_cancel(false)
    41→        , _is_sync(false)
    42→        , _timeout_id(0)
    43→    {}
    44→
    45→    virtual ~RpcControllerImpl() {}
    46→
    47→    void SetRequestCompressType(CompressType compress_type)
    48→    {
    49→        _user_options.request_compress_type = compress_type;
    50→    }
    51→
    52→    CompressType RequestCompressType()
    53→    {
    54→        return _user_options.request_compress_type != CompressTypeAuto ?
    55→            _user_options.request_compress_type : _auto_options.request_compress_type;
    56→    }
    57→
    58→    void SetResponseCompressType(CompressType compress_type)
    59→    {
    60→        _user_options.response_compress_type = compress_type;
    61→    }
    62→
    63→    CompressType ResponseCompressType()
    64→    {
    65→        return _user_options.response_compress_type != CompressTypeAuto ?
    66→            _user_options.response_compress_type : _auto_options.response_compress_type;
    67→    }
    68→
    69→    void SetTimeout(int64 timeout)
    70→    {
    71→        _user_options.timeout = timeout;
    72→    }
    73→
    74→    int64 Timeout() const
    75→    {
    76→        return _user_options.timeout > 0 ?
    77→            _user_options.timeout : _auto_options.timeout;
    78→    }
    79→
    80→    bool Failed() const
    81→    {
    82→        return _error_code != RPC_SUCCESS;
    83→    }
    84→
    85→    int ErrorCode() const
    86→    {
    87→        return _error_code;
    88→    }
    89→
    90→    const std::string& Reason() const
    91→    {
    92→        return _reason;
    93→    }
    94→
    95→    std::string ErrorText() const
    96→    {
    97→        if (_reason.empty()) {
    98→            return RpcErrorCodeToString(_error_code);
    99→        } else {
   100→            return RpcErrorCodeToString(_error_code)
   101→                + std::string(": ") + _reason;
   102→        }
   103→    }
   104→
   105→    void StartCancel()
   106→    {
   107→        // TODO to support
   108→    }
   109→
   110→    void SetFailed(const std::string& reason)
   111→    {
   112→        SetFailed(RPC_ERROR_FROM_USER, reason);
   113→    }
   114→
   115→    bool IsCanceled() const
   116→    {
   117→        // TODO to support
   118→        return false;
   119→    }
   120→
   121→    void NotifyOnCancel(google::protobuf::Closure* /* callback */)
   122→    {
   123→        // TODO to support
   124→    }
   125→
   126→
   127→    // -----------------------------------------------------------------
   128→    // Used both in client and server.
   129→    // -----------------------------------------------------------------
   130→    void SetSequenceId(uint64 sequence_id)
   131→    {
   132→        _sequence_id = sequence_id;
   133→    }
   134→
   135→    uint64 SequenceId() const
   136→    {
   137→        return _sequence_id;
   138→    }
   139→
   140→    void SetMethodId(const std::string& method_id)
   141→    {
   142→        _method_id = method_id;
   143→    }
   144→
   145→    const std::string& MethodId() const
   146→    {
   147→        return _method_id;
   148→    }
   149→
   150→    void SetLocalEndpoint(const RpcEndpoint& local_endpoint)
   151→    {
   152→        _local_endpoint = local_endpoint;
   153→    }
   154→
   155→    const RpcEndpoint& LocalEndpoint() const
   156→    {
   157→        return _local_endpoint;
   158→    }
   159→
   160→    void SetRemoteEndpoint(const RpcEndpoint& remote_endpoint)
   161→    {
   162→        _remote_endpoint = remote_endpoint;
   163→    }
   164→
   165→    const RpcEndpoint& RemoteEndpoint() const
   166→    {
   167→        return _remote_endpoint;
   168→    }
   169→
   170→    void SetFailed(int error_code, const std::string& reason)
   171→    {
   172→        _error_code = error_code;
   173→        _reason = reason;
   174→        if (_error_code == RPC_ERROR_REQUEST_TIMEOUT)
   175→        {
   176→            _reason += _is_request_sent ?
   177→                ": request already sent to remote" :
   178→                ": request not sent to remote";
   179→        }
   180→    }
   181→
   182→
   183→    // -----------------------------------------------------------------
   184→    // Used only in client.
   185→    // -----------------------------------------------------------------
   186→    bool IsDone() const
   187→    {
   188→        return _is_done == DONE;
   189→    }
   190→
   191→    bool IsRequestSent() const
   192→    {
   193→        return _is_request_sent;
   194→    }
   195→
   196→    int64 SentBytes() const
   197→    {
   198→        return _sent_bytes;
   199→    }
   200→
   201→    bool IsStartCancel() const
   202→    {
   203→        return _is_start_cancel;
   204→    }
   205→
   206→    void PushDoneCallback(const InternalDoneCallback& callback)
   207→    {
   208→        SCHECK(callback);
   209→        _done_callbacks.push_back(callback);
   210→    }
   211→
   212→    void Done(int error_code, const std::string& reason)
   213→    {
   214→        // make sure that the callback is only called once.
   215→        if (atomic_comp_swap(&_is_done, DONE, NOT_DONE) == NOT_DONE)
   216→        {
   217→            SetFailed(error_code, reason);
   218→
   219→            while (!_done_callbacks.empty())
   220→            {
   221→                const InternalDoneCallback& callback = _done_callbacks.back();
   222→                callback(shared_from_this());
   223→                _done_callbacks.pop_back();
   224→            }
   225→        }
   226→    }
   227→
   228→    void FillFromMethodDescriptor(const google::protobuf::MethodDescriptor* method)
   229→    {
   230→        _method_id = method->full_name();
   231→        if (_user_options.timeout <= 0)
   232→        {
   233→            int64 timeout_in_ms = method->options().HasExtension(method_timeout) ?
   234→                method->options().GetExtension(method_timeout) :
   235→                method->service()->options().GetExtension(service_timeout);
   236→            if (timeout_in_ms <= 0) {
   237→                // Just a protection, it shouldn't happen.
   238→                timeout_in_ms = 1;
   239→            }
   240→            _auto_options.timeout = timeout_in_ms;
   241→        }
   242→        if (_user_options.request_compress_type == CompressTypeAuto) {
   243→            _auto_options.request_compress_type =
   244→                method->options().HasExtension(request_compress_type) ?
   245→                method->options().GetExtension(request_compress_type) :
   246→                CompressTypeNone;
   247→        }
   248→        if (_user_options.response_compress_type == CompressTypeAuto) {
   249→            _auto_options.response_compress_type =
   250→                method->options().HasExtension(response_compress_type) ?
   251→                method->options().GetExtension(response_compress_type) :
   252→                CompressTypeNone;
   253→        }
   254→    }
   255→
   256→    void SetSync()
   257→    {
   258→        _is_sync = true;
   259→    }
   260→
   261→    bool IsSync() const
   262→    {
   263→        return _is_sync;
   264→    }
   265→
   266→    void SetWaitEvent(const WaitEventPtr& wait_event)
   267→    {
   268→        _wait_event = wait_event;
   269→    }
   270→
   271→    const WaitEventPtr& WaitEvent() const
   272→    {
   273→        return _wait_event;
   274→    }
   275→
   276→    void SetRpcClientStream(const RpcClientStreamWPtr& stream)
   277→    {
   278→        _client_stream = stream;
   279→    }
   280→
   281→    const RpcClientStreamWPtr& RpcClientStream() const
   282→    {
   283→        return _client_stream;
   284→    }
   285→
   286→    void StartTimer()
   287→    {
   288→        int64 timeout = Timeout();
   289→        _expiration = timeout <= 0 ? ptime_infin()
   290→            : ptime_now() + time_duration_milliseconds(timeout);
   291→    }
   292→
   293→    const PTime& Expiration() const
   294→    {
   295→        return _expiration;
   296→    }
   297→
   298→    void SetTimeoutId(uint64 timeout_id)
   299→    {
   300→        _timeout_id = timeout_id;
   301→    }
   302→
   303→    uint64 TimeoutId() const
   304→    {
   305→        return _timeout_id;
   306→    }
   307→
   308→    void SetRequestBuffer(const ReadBufferPtr& request_buffer)
   309→    {
   310→        _request_buffer = request_buffer;
   311→    }
   312→
   313→    const ReadBufferPtr& RequestBuffer() const
   314→    {
   315→        return _request_buffer;
   316→    }
   317→
   318→    void SetResponseBuffer(const ReadBufferPtr& response_buffer)
   319→    {
   320→        _response_buffer = response_buffer;
   321→    }
   322→
   323→    const ReadBufferPtr& ResponseBuffer() const
   324→    {
   325→        return _response_buffer;
   326→    }
   327→
   328→    void NotifyRequestSent(const RpcEndpoint& local_endpoint, int64 sent_bytes)
   329→    {
   330→        _is_request_sent = true;
   331→        _local_endpoint = local_endpoint;
   332→        _sent_bytes = sent_bytes;
   333→        _request_sent_time = ptime_now();
   334→    }
   335→
   336→
   337→    // -----------------------------------------------------------------
   338→    // Used only in server.
   339→    // -----------------------------------------------------------------
